// End-to-end tests that run the aggregator through `act` and parse its output,
// plus lightweight YAML-structure assertions. All functional testing happens
// via the GitHub Actions workflow per the task requirements.

import { afterAll, beforeAll, describe, expect, test } from "bun:test";
import { existsSync, mkdtempSync, readFileSync, rmSync } from "node:fs";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { spawnSync } from "node:child_process";

const ROOT = import.meta.dir;
const ACT_RESULTS = join(ROOT, "act-result.txt");

// --- Workflow structure tests --------------------------------------------

describe("workflow structure", () => {
  const wfPath = join(ROOT, ".github/workflows/test-results-aggregator.yml");

  test("workflow file exists", () => {
    expect(existsSync(wfPath)).toBe(true);
  });

  test("actionlint passes", () => {
    const r = spawnSync("actionlint", [wfPath], { encoding: "utf8" });
    expect(r.stdout + r.stderr).toBe("");
    expect(r.status).toBe(0);
  });

  test("declares the expected triggers, job and steps", () => {
    const text = readFileSync(wfPath, "utf8");
    // Triggers
    expect(text).toMatch(/^on:/m);
    expect(text).toMatch(/push:/);
    expect(text).toMatch(/pull_request:/);
    expect(text).toMatch(/workflow_dispatch:/);
    expect(text).toMatch(/schedule:/);
    // Job + checkout
    expect(text).toMatch(/runs-on:\s*ubuntu-latest/);
    expect(text).toMatch(/actions\/checkout@v4/);
    expect(text).toMatch(/oven-sh\/setup-bun@v1/);
    // References our scripts
    expect(text).toMatch(/cli\.ts/);
    expect(text).toMatch(/bun test/);
  });

  test("referenced files exist", () => {
    expect(existsSync(join(ROOT, "cli.ts"))).toBe(true);
    expect(existsSync(join(ROOT, "aggregator.ts"))).toBe(true);
    expect(existsSync(join(ROOT, "fixtures"))).toBe(true);
  });
});

// --- act end-to-end tests -----------------------------------------------

// Each case sets up an isolated temp git repo with the project files plus a
// fresh `fixtures/` directory containing only that case's inputs, then runs
// `act push --rm` and asserts on the observed output.
interface ActCase {
  name: string;
  // files to place under fixtures/
  fixtures: Record<string, string>;
  // substrings that must appear in act output (the workflow runs `cat summary.md`
  // so the rendered markdown surfaces in the captured log).
  expect: string[];
  // key=value lines printed by cli.ts that must match exactly.
  kv: Record<string, string>;
}

const cases: ActCase[] = [
  {
    name: "no-flaky-all-pass",
    fixtures: {
      "a.xml": `<?xml version="1.0"?><testsuites><testsuite name="s" tests="2" time="1.0"><testcase classname="c" name="x" time="0.5"/><testcase classname="c" name="y" time="0.5"/></testsuite></testsuites>`,
      "b.json": JSON.stringify({
        tests: [
          { name: "c.x", status: "passed", duration: 0.4 },
          { name: "c.y", status: "passed", duration: 0.4 },
        ],
      }),
    },
    expect: ["Test Results: PASSED", "_None detected._"],
    kv: {
      AGG_PASSED: "4",
      AGG_FAILED: "0",
      AGG_SKIPPED: "0",
      AGG_TOTAL: "4",
      AGG_FLAKY: "0",
      AGG_FLAKY_NAMES: "",
    },
  },
  {
    name: "flaky-detected",
    fixtures: {
      "run1.xml": `<?xml version="1.0"?><testsuites><testsuite name="s" tests="2" time="1.0"><testcase classname="c" name="stable" time="0.1"/><testcase classname="c" name="wobble" time="0.2"><failure message="x">x</failure></testcase></testsuite></testsuites>`,
      "run2.json": JSON.stringify({
        tests: [
          { name: "c.stable", status: "passed", duration: 0.1 },
          { name: "c.wobble", status: "passed", duration: 0.2 },
        ],
      }),
    },
    expect: ["Test Results: FAILED", "Flaky Tests", "c.wobble"],
    kv: {
      AGG_PASSED: "3",
      AGG_FAILED: "1",
      AGG_SKIPPED: "0",
      AGG_TOTAL: "4",
      AGG_FLAKY: "1",
      AGG_FLAKY_NAMES: "c.wobble",
    },
  },
  {
    name: "with-skipped",
    fixtures: {
      "only.xml": `<?xml version="1.0"?><testsuites><testsuite name="s" tests="3" time="1.0"><testcase classname="c" name="ok" time="0.1"/><testcase classname="c" name="later" time="0.0"><skipped/></testcase><testcase classname="c" name="bad" time="0.2"><failure message="x">x</failure></testcase></testsuite></testsuites>`,
    },
    expect: ["Test Results: FAILED", "Skipped | 1"],
    kv: {
      AGG_PASSED: "1",
      AGG_FAILED: "1",
      AGG_SKIPPED: "1",
      AGG_TOTAL: "3",
      AGG_FLAKY: "0",
      AGG_FLAKY_NAMES: "",
    },
  },
];

function hasDocker(): boolean {
  const r = spawnSync("docker", ["info"], { encoding: "utf8" });
  return r.status === 0;
}

function runActCase(c: ActCase, repo: string): { output: string; code: number } {
  // Copy project files into isolated repo
  const copy = spawnSync(
    "bash",
    [
      "-c",
      `set -e
       cp -r "${ROOT}/aggregator.ts" "${ROOT}/cli.ts" "${ROOT}/package.json" "${ROOT}/tsconfig.json" "${repo}/"
       mkdir -p "${repo}/.github/workflows" "${repo}/fixtures"
       cp "${ROOT}/.github/workflows/test-results-aggregator.yml" "${repo}/.github/workflows/"
       cp "${ROOT}/aggregator.test.ts" "${repo}/"
       [ -f "${ROOT}/bun.lock" ] && cp "${ROOT}/bun.lock" "${repo}/" || true
       [ -f "${ROOT}/.actrc" ] && cp "${ROOT}/.actrc" "${repo}/" || true
       cd "${repo}"
       git init -q
       git config user.email ci@example.com
       git config user.name ci
       git add -A
       git commit -q -m initial`,
    ],
    { encoding: "utf8" },
  );
  if (copy.status !== 0) {
    return { output: `setup failed: ${copy.stdout}\n${copy.stderr}`, code: 99 };
  }

  // Write fixtures for this case (after git init so any prior ones are absent)
  for (const [name, contents] of Object.entries(c.fixtures)) {
    Bun.write(join(repo, "fixtures", name), contents);
  }
  // commit fixtures
  spawnSync("bash", ["-c", `cd "${repo}" && git add -A && git commit -q -m fixtures`], {
    encoding: "utf8",
  });

  const r = spawnSync("act", ["push", "--rm"], {
    cwd: repo,
    encoding: "utf8",
    env: { ...process.env },
    timeout: 10 * 60 * 1000,
  });
  return { output: (r.stdout ?? "") + (r.stderr ?? ""), code: r.status ?? -1 };
}

const dockerOK = hasDocker();

beforeAll(() => {
  // Fresh act-result.txt per harness run; each case appends to it.
  Bun.write(ACT_RESULTS, "");
});

describe.if(dockerOK)("act end-to-end", () => {
  const repos: string[] = [];
  afterAll(() => {
    for (const r of repos) rmSync(r, { recursive: true, force: true });
  });

  for (const c of cases) {
    test(
      c.name,
      async () => {
        const repo = mkdtempSync(join(tmpdir(), `agg-${c.name}-`));
        repos.push(repo);
        const { output, code } = runActCase(c, repo);

        // Append to act-result.txt with clear delimiter
        const delim = `\n===== CASE: ${c.name} (exit ${code}) =====\n`;
        const current = existsSync(ACT_RESULTS) ? readFileSync(ACT_RESULTS, "utf8") : "";
        await Bun.write(ACT_RESULTS, current + delim + output + "\n");

        expect(code).toBe(0);
        expect(output).toContain("Job succeeded");
        for (const s of c.expect) expect(output).toContain(s);
        for (const [k, v] of Object.entries(c.kv)) {
          // Each key=value line printed by cli.ts must appear verbatim.
          expect(output).toContain(`${k}=${v}`);
        }
      },
      15 * 60 * 1000,
    );
  }
});

if (!dockerOK) {
  // Surface a clear signal rather than silently skipping.
  test.skip("act end-to-end (docker unavailable)", () => {});
}

