    kv: {
      AGG_PASSED: "1",
      AGG_FAILED: "1",
      AGG_SKIPPED: "1",
      AGG_TOTAL: "3",
      AGG_FLAKY: "0",
      AGG_FLAKY_NAMES: "",
    },
  },
];

function setupRepo(repo: string): void {
  const cmd = `set -e
    cp "${ROOT}/aggregator.ts" "${ROOT}/aggregator.test.ts" "${ROOT}/cli.ts" "${ROOT}/package.json" "${ROOT}/tsconfig.json" "${repo}/"
