    } else {
      allPassed = false;
      console.error(`FAIL: ${c.name}`);
      for (const r of reasons) console.error(`  - ${r}`);
    }
  }
  console.log(`\nact-result.txt written to ${ACT_RESULTS}`);
  return allPassed ? 0 : 1;
}

process.exit(await main());

